// Shared transform for Drupal-handoff "DVersion" bundles.
//
// Each microsite that wants a Drupal-droppable variant has its own
// build.mjs that imports buildDversion() and supplies a small config
// describing the source .njk, the namespace class, and the human
// labels for the preview harness. Everything else — front-matter
// stripping, @import hoisting, @scope wrapping, IIFE/Proxy JS scoping,
// inline-handler exposure, themed-mode body re-application, the
// preview harness — is handled here.
//
// Output: dist/{NAME}.{html,css,js} + preview/index.html

import { readFileSync, writeFileSync, mkdirSync } from 'node:fs';
import { resolve } from 'node:path';

// Source body rules become the themed-mode root styles. These
// declarations don't make sense for an embedded partial and are
// dropped before re-application.
const BODY_DECLS_TO_DROP = new Set([
  'min-height',          // would force the partial to 100vh inside Drupal
  'overflow-x',          // host page owns scroll
  'overflow-y',
  'overscroll-behavior',
  'scroll-behavior',
]);

function extractFrontMatter(src) {
  if (!src.startsWith('---')) return src;
  const end = src.indexOf('---', 3);
  if (end < 0) throw new Error('No front-matter terminator found');
  return src.slice(end + 3);
}

function extractBlocks(text, openTag, closeTag) {
  const re = new RegExp(`<${openTag}>([\\s\\S]*?)<\\/${closeTag}>`, 'g');
  const blocks = [];
  let m;
  while ((m = re.exec(text)) !== null) blocks.push(m[1]);
  return { blocks, re };
}

function stripBlock(text, re) {
  return text.replace(re, '');
}

function applyStripPatterns(body, patterns) {
  for (const pat of patterns) body = body.replace(pat, '');
  return body;
}

// Pull `body { … }` declarations out of the CSS so we can re-emit them
// inside .NS--themed. Returns {css, bodyDecls} where bodyDecls is the
// inner declarations (newline-joined, ready to inline into a rule).
function extractBodyRule(css) {
  let bodyDecls = '';
  const re = /(^|\n)\s*body\s*\{([^}]*)\}/g;
  css = css.replace(re, (_, prefix, decls) => {
    const kept = decls
      .split(';')
      .map((d) => d.trim())
      .filter(Boolean)
      .filter((d) => {
        const prop = d.split(':')[0]?.trim().toLowerCase();
        return prop && !BODY_DECLS_TO_DROP.has(prop);
      });
    bodyDecls += kept.map((d) => '  ' + d + ';').join('\n') + '\n';
    return prefix; // strip the rule from the scoped block
  });
  return { css, bodyDecls: bodyDecls.trim() };
}

// `@import url(...)` is invalid inside `@scope`; hoist to the top.
function hoistImports(css) {
  const imports = [];
  css = css.replace(/@import\s+url\([^)]+\)\s*;?/g, (m) => {
    imports.push(m.trim().replace(/;?$/, ';'));
    return '';
  });
  return { css, imports };
}

// Pull a single  .NS { … }  block out of the CSS (after :root → .NS
// promotion) so we can emit it OUTSIDE @scope. This is required because
// inside  @scope (.NS) { ... } , the selector  .NS { ... }  matches a
// .NS element nested inside the scoping root, NOT the scoping root
// itself — so design tokens defined that way never reach the partial
// root and every  var(--foo)  resolves to nothing. Hoisting them
// outside @scope sets them on the root, where they cascade inward.
function extractRootTokens(css, ns) {
  let tokens = '';
  const re = new RegExp(`(^|\\n)\\s*\\.${ns}\\s*\\{([^}]*)\\}`);
  css = css.replace(re, (_, prefix, decls) => {
    tokens = decls.trim();
    return prefix;
  });
  return { css, tokens };
}

function transformCss({ rawCss, ns }) {
  let css = rawCss;
  const { css: c1, imports } = hoistImports(css);
  css = c1;
  // :root → .NS so design tokens are scope-local
  css = css.replace(/:root\s*\{/g, `.${ns} {`);
  // strip top-level html{} (would do nothing inside @scope but is noise)
  css = css.replace(/(^|\n)\s*html\s*\{[^}]*\}/g, '$1');
  // pull body{} into themed-mode root
  const { css: c2, bodyDecls } = extractBodyRule(css);
  css = c2;
  // hoist .NS{--vars} block out of @scope so it actually applies to root
  const { css: c3, tokens: rootTokens } = extractRootTokens(css, ns);
  css = c3;

  const lines = [
    `/* Scoped to .${ns} via CSS @scope. Generated by`,
    `   microsites/_dversion-build.mjs — do not edit dist/ by hand. */`,
    ``,
    ...imports,
    imports.length ? '' : null,
    rootTokens
      ? [
          `/* Design tokens for the partial root. Defined OUTSIDE @scope so`,
          `   they actually set custom properties on the .${ns} element`,
          `   (inside @scope, .${ns} would only match descendants of the root). */`,
          `.${ns} {`,
          rootTokens.split('\n').map((l) => '  ' + l.trim()).join('\n'),
          `}`,
          ``,
        ].join('\n')
      : null,
    `@scope (.${ns}) {`,
    css.trim(),
    `}`,
    ``,
    `/* Default (un-themed) mode: redefine typography/text tokens to`,
    `   "inherit" so descendant rules using those vars resolve to the`,
    `   host page's font and color. Brand accent colors stay so the`,
    `   partial keeps its identity. */`,
    `.${ns}:not(.${ns}--themed) {`,
    `  --display: inherit;`,
    `  --body: inherit;`,
    `  --serif: inherit;`,
    `  --sans: inherit;`,
    `  --mono: ui-monospace, monospace;`,
    `  --ink: inherit;`,
    `  --ink-soft: inherit;`,
    `  --ink-faint: inherit;`,
    `  --ink-mid: inherit;`,
    `  --ink-mute: inherit;`,
    `  font-family: inherit;`,
    `  color: inherit;`,
    `  background: transparent;`,
    `}`,
    ``,
    bodyDecls
      ? [
          `/* Themed mode: re-apply the source page's  body { … }  declarations`,
          `   to the partial root so the catalog renders with its full visual`,
          `   identity (background, typography, smoothing, gradients). */`,
          `.${ns}.${ns}--themed {`,
          bodyDecls,
          `}`,
          ``,
        ].join('\n')
      : null,
  ].filter((l) => l !== null);
  return lines.join('\n');
}

// Detect functions that need to live on `window` because inline on*
// attributes call them. Scans both the static body markup AND the JS
// source — the JS often emits HTML strings containing onclick="…", so a
// body-only scan misses dynamic handlers (e.g. openModal('id') in a
// card-rendering template string). Also handles attribute values that
// start with `return ` like  onsubmit="return submitRec(event)".
//
// IMPORTANT: a name only counts if it's actually DECLARED at the top
// level of the JS source (function foo, const foo = …, let foo = …,
// var foo = …). Inline attribute values frequently call methods on
// other objects — event.preventDefault(), classList.toggle(),
// document.getElementById() — and the regex would otherwise pick up
// "preventDefault", "toggle", "getElementById" as handler names. The
// IIFE then crashes on  window.preventDefault = preventDefault  because
// no such top-level binding exists.
function detectInlineHandlers(body, js) {
  // 1. Collect every identifier-followed-by-( inside an on* attribute.
  const candidates = new Set();
  const haystack = body + '\n' + js;
  const callRe = /\son[a-z]+\s*=\s*["'][^"']*?\b([a-zA-Z_$][\w$]*)\s*\(/g;
  for (let m; (m = callRe.exec(haystack)) !== null; ) {
    if (m[1] === 'return') continue;
    candidates.add(m[1]);
  }

  // 2. Collect every name actually declared at the top level of the
  //    JS source. Indentation is NOT a reliable "top level" heuristic
  //    when the source is HTML-embedded — the <script> block content is
  //    typically indented two or four spaces under the tag, so an
  //    anchored ^function would miss every declaration. The intersection
  //    step below filters by inline-handler reference, so a permissive
  //    declaration scan only matters when an inner-block name happens to
  //    collide with an inline handler call (rare; the symptom would be
  //    a runtime ReferenceError in the IIFE, which surfaces immediately).
  const declared = new Set();
  const declRe = /(?:^|\n)[ \t]*(?:function\s+([a-zA-Z_$][\w$]*)|(?:const|let|var)\s+([a-zA-Z_$][\w$]*)\s*=)/g;
  for (let m; (m = declRe.exec(js)) !== null; ) {
    const name = m[1] || m[2];
    if (name) declared.add(name);
  }

  // 3. Intersect — only expose names the source actually defines.
  return [...candidates].filter((n) => declared.has(n));
}

function transformJs({ rawJs, ns, handlers }) {
  const exposeLines = handlers.map((n) => `  window.${n} = ${n};`);
  return [
    `// Scoped to .${ns}. Generated by microsites/_dversion-build.mjs.`,
    `(function () {`,
    `  // Use window.document explicitly here — declaring  const document`,
    `  // = …  later in this scope hoists the binding to the top of the`,
    `  // function as TDZ, so plain  document.querySelector  on this line`,
    `  // would throw "Cannot access 'document' before initialization".`,
    `  const ROOT = window.document.querySelector('.${ns}');`,
    `  if (!ROOT) return;`,
    ``,
    `  // Re-bind document.* lookups to resolve against the partial root,`,
    `  // so IDs and class selectors can't collide with the host Drupal page.`,
    `  const document = new Proxy(window.document, {`,
    `    get(target, prop) {`,
    `      if (prop === 'getElementById') return (id) => ROOT.querySelector('#' + CSS.escape(id));`,
    `      if (prop === 'querySelector') return (sel) => ROOT.querySelector(sel);`,
    `      if (prop === 'querySelectorAll') return (sel) => ROOT.querySelectorAll(sel);`,
    `      const v = target[prop];`,
    `      return typeof v === 'function' ? v.bind(target) : v;`,
    `    },`,
    `  });`,
    ``,
    rawJs.trim(),
    ``,
    exposeLines.length
      ? `  // Expose handlers used by inline on* attributes (the IIFE would otherwise hide them).\n${exposeLines.join('\n')}`
      : `  // (No inline on* handlers detected — nothing to expose on window.)`,
    `})();`,
    ``,
  ].join('\n');
}

function buildPartial({ ns, fileBase, prettyName, body }) {
  return [
    `<!-- ${prettyName} — Drupal partial.`,
    `     Generated by microsites/_dversion-build.mjs.`,
    `     Drop into a Drupal Custom Block (Source/HTML view) and attach`,
    `     ${fileBase}.css and ${fileBase}.js as a library. -->`,
    ``,
    `<!-- Add  ${ns}--themed  to the root for the cheetochopsticks palette;`,
    `     omit it to inherit the host site's typography and color. -->`,
    `<div class="${ns}">`,
    body.trim(),
    `</div>`,
    ``,
  ].join('\n');
}

function buildPreview({ ns, fileBase, prettyName, hostNav, hostHeadline, scopedCss, scopedJs, partial, previewFontHrefs = [], previewExtraScripts = [] }) {
  const fontLinks = previewFontHrefs.length
    ? [
        `<link rel="preconnect" href="https://fonts.googleapis.com">`,
        `<link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>`,
        ...previewFontHrefs.map((href) => `<link href="${href}" rel="stylesheet">`),
      ]
    : [];
  // External libraries the partial JS depends on (e.g. Leaflet for the
  // alerts page). Emitted as plain <script src> in the head with no defer
  // / async attributes so they're available synchronously by the time the
  // inline <script id="…-js"> block runs further down the document.
  const extraScriptTags = previewExtraScripts.map((s) => {
    if (typeof s === 'string') return `<script src="${s}"></script>`;
    const attrs = Object.entries(s.attrs ?? {})
      .map(([k, v]) => v === true ? ` ${k}` : ` ${k}="${v}"`)
      .join('');
    return `<script src="${s.src}"${attrs}></script>`;
  });
  return [
    `<!doctype html>`,
    `<html lang="en">`,
    `<head>`,
    `<meta charset="utf-8">`,
    `<title>${prettyName} DVersion — preview harness</title>`,
    `<meta name="viewport" content="width=device-width, initial-scale=1">`,
    ...fontLinks,
    ...extraScriptTags,
    `<style>`,
    `  :root {`,
    `    --host-bg: #f4f1ec;`,
    `    --host-fg: #1d2733;`,
    `    --host-accent: #1a4f8b;`,
    `    --host-rule: #c9c2b6;`,
    `  }`,
    `  html, body { margin: 0; background: var(--host-bg); color: var(--host-fg);`,
    `               font: 16px/1.55 'Times New Roman', Georgia, serif; }`,
    `  .host-bar { background: var(--host-accent); color: #fff; padding: 12px 20px; font-size: 14px; }`,
    `  .host-nav { background: #fff; border-bottom: 1px solid var(--host-rule); padding: 14px 20px; }`,
    `  .host-nav strong { font-size: 18px; color: var(--host-accent); }`,
    `  .host-content { max-width: 1240px; margin: 0 auto; padding: 28px 20px; }`,
    `  .host-content > h1 { font: 30px/1.2 'Times New Roman', Georgia, serif; margin: 0 0 8px; }`,
    `  .host-content > p { margin: 0 0 18px; max-width: 64ch; }`,
    `  .host-toggle { display: inline-flex; gap: 8px; margin: 12px 0 24px; padding: 6px;`,
    `                 border: 1px solid var(--host-rule); border-radius: 6px; background: #fff; }`,
    `  .host-toggle button { border: 0; padding: 6px 12px; cursor: pointer; font: inherit;`,
    `                        color: var(--host-fg); background: transparent; border-radius: 4px;`,
    `                        min-height: 36px; }`,
    `  .host-toggle button[aria-pressed="true"] { background: var(--host-accent); color: #fff; }`,
    `  .host-toggle button:focus-visible { outline: 3px solid var(--host-accent); outline-offset: 2px; }`,
    `  .host-footer { border-top: 1px solid var(--host-rule); padding: 18px 20px;`,
    `                 color: #555; font-size: 13px; text-align: center; }`,
    `</style>`,
    `<style id="${fileBase}-css">`,
    scopedCss,
    `</style>`,
    `</head>`,
    `<body>`,
    `<div class="host-bar">cheetochopsticks.gov · simulated Drupal host page</div>`,
    `<div class="host-nav"><strong>City of Colorado Springs</strong> &nbsp; · &nbsp; ${hostNav}</div>`,
    `<main class="host-content">`,
    `  <h1>${hostHeadline}</h1>`,
    `  <p>The block below is the <code>${ns}</code> partial. Use the toggle to compare default (inherit host typography) vs. themed (cheetochopsticks).</p>`,
    `  <div class="host-toggle" role="group" aria-label="Theme mode">`,
    `    <button id="mode-inherit" aria-pressed="true">Default (inherit host)</button>`,
    `    <button id="mode-themed" aria-pressed="false">Themed (cheetochopsticks)</button>`,
    `  </div>`,
    partial.trim(),
    `</main>`,
    `<div class="host-footer">© Simulated Drupal host page · the partial above is fully scoped.</div>`,
    `<script id="${fileBase}-js">`,
    scopedJs,
    `</script>`,
    `<script>`,
    `(function () {`,
    `  const root = () => document.querySelector('.${ns}');`,
    `  const setMode = (themed) => {`,
    `    const r = root(); if (!r) return;`,
    `    r.classList.toggle('${ns}--themed', themed);`,
    `    document.getElementById('mode-inherit').setAttribute('aria-pressed', String(!themed));`,
    `    document.getElementById('mode-themed').setAttribute('aria-pressed', String(themed));`,
    `  };`,
    `  document.getElementById('mode-inherit').addEventListener('click', () => setMode(false));`,
    `  document.getElementById('mode-themed').addEventListener('click', () => setMode(true));`,
    `})();`,
    `</script>`,
    `</body>`,
    `</html>`,
    ``,
  ].join('\n');
}

/**
 * @param {object} cfg
 * @param {string}   cfg.src           absolute path to source .njk
 * @param {string}   cfg.outDir        absolute path to dist/ output folder
 * @param {string}   cfg.previewDir    absolute path to preview/ output folder
 * @param {string}   cfg.ns            CSS namespace class (e.g. "cc-forestry")
 * @param {string}   cfg.fileBase      base filename for dist outputs (e.g. "forestry")
 * @param {string}   cfg.prettyName    human label (e.g. "Trees for Colorado Springs")
 * @param {string}   cfg.hostNav       simulated Drupal nav text
 * @param {string}   cfg.hostHeadline  simulated host-page H1
 * @param {RegExp[]} [cfg.stripPatterns]    regex patterns to strip from body markup
 *                                          (e.g. site headers/footers that Drupal owns)
 * @param {string[]} [cfg.previewFontHrefs] webfont stylesheet URLs to <link> in the
 *                                          preview harness so themed mode renders
 *                                          with real fonts. Sources that load fonts
 *                                          via @import don't need this — those are
 *                                          already hoisted into the scoped CSS.
 * @param {Array<string|{src:string,attrs?:object}>} [cfg.previewExtraScripts]
 *                                          External JS dependencies the partial
 *                                          needs at runtime (e.g. Leaflet for
 *                                          a map page). Emitted as <script src>
 *                                          tags in the preview's <head> so they
 *                                          load before the partial's IIFE runs.
 *                                          The production Drupal/WordPress host
 *                                          must enqueue these separately — the
 *                                          dist files don't include them.
 * @param {string}   [cfg.previewName]      preview filename within previewDir
 *                                          (default: "index.html"). Set per-page
 *                                          when a parent folder hosts multiple
 *                                          DVersions in one preview directory.
 */
export function buildDversion(cfg) {
  const { src, outDir, previewDir, ns, fileBase, prettyName, hostNav, hostHeadline } = cfg;
  const stripPatterns = cfg.stripPatterns ?? [];
  const previewFontHrefs = cfg.previewFontHrefs ?? [];
  const previewExtraScripts = cfg.previewExtraScripts ?? [];
  const previewName = cfg.previewName ?? 'index.html';

  const raw = readFileSync(src, 'utf8');
  const afterFm = extractFrontMatter(raw);

  const styles = extractBlocks(afterFm, 'style', 'style');
  const scripts = extractBlocks(afterFm, 'script', 'script');

  let body = afterFm;
  body = stripBlock(body, styles.re);
  body = stripBlock(body, scripts.re);
  body = applyStripPatterns(body, stripPatterns).trim();

  const rawCss = styles.blocks.join('\n\n/* --- */\n\n');
  const scopedCss = transformCss({ rawCss, ns });

  const rawJs = scripts.blocks.join('\n\n// --- next script block ---\n\n');
  const handlers = detectInlineHandlers(body, rawJs);
  const scopedJs = transformJs({ rawJs, ns, handlers });

  const partial = buildPartial({ ns, fileBase, prettyName, body });
  const previewHtml = buildPreview({
    ns, fileBase, prettyName, hostNav, hostHeadline,
    scopedCss, scopedJs, partial, previewFontHrefs, previewExtraScripts,
  });

  mkdirSync(outDir, { recursive: true });
  writeFileSync(resolve(outDir, `${fileBase}.html`), partial);
  writeFileSync(resolve(outDir, `${fileBase}.css`), scopedCss);
  writeFileSync(resolve(outDir, `${fileBase}.js`), scopedJs);

  mkdirSync(previewDir, { recursive: true });
  writeFileSync(resolve(previewDir, previewName), previewHtml);

  console.log(
    `${prettyName} DVersion built:\n` +
    `  ${outDir}/${fileBase}.html  (${partial.length.toLocaleString()} bytes)\n` +
    `  ${outDir}/${fileBase}.css   (${scopedCss.length.toLocaleString()} bytes)\n` +
    `  ${outDir}/${fileBase}.js    (${scopedJs.length.toLocaleString()} bytes)\n` +
    `  ${previewDir}/${previewName}  (${previewHtml.length.toLocaleString()} bytes, self-contained)\n` +
    `  hoisted ${(scopedCss.match(/^@import/gm) || []).length} @import; ` +
    `exposed ${handlers.length} inline handler(s); ` +
    `body styles re-applied in themed mode.`,
  );
}
